const inputs = $input.all();
const items = [];
for (const input of inputs) {
  const xml = input.json.data;
  if (!xml) continue;
  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
  let match;
  while ((match = itemRegex.exec(xml)) !== null) {
    const item = match[1];
    const title = (item.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/) || item.match(/<title>(.*?)<\/title>/))?.[1] || 'Sans titre';
    const link = (item.match(/<link>(.*?)<\/link>/) || [])[1] || '';
    const description = (item.match(/<description><!\[CDATA\[(.*?)\]\]><\/description>/) || item.match(/<description>(.*?)<\/description>/))?.[1] || '';
    const pubDate = (item.match(/<pubDate>(.*?)<\/pubDate>/) || [])[1] || '';
    let source = '🌐 Autre';
    if (link.includes('cert.ssi.gouv.fr')) source = '🇫🇷 CERT-FR';
    else if (link.includes('cyber.gouv.fr')) source = '🇫🇷 ANSSI';
    else if (link.includes('grahamcluley.com')) source = '🔎 Graham Cluley';
    else if (link.includes('krebsonsecurity.com') || link.includes('bitdefender.com')) source = '🔐 Krebs on Security';
    const prompt = 'Résume cet article de cybersécurité en 2 phrases maximum en français, de façon claire et professionnelle. Titre : ' + title + ' Contenu : ' + description.substring(0, 400);
    items.push({ json: { title, link, description: description.substring(0, 400), pubDate, source, prompt } });
  }
}
return items.sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate)).slice(0, 5);

const items = $input.all();
const lines = items.map(item => {
  const resume = item.json.choices?.[0]?.message?.content || 'Résumé indisponible';
  const inputData = $('PARSER RSS').all();
  const index = items.indexOf(item);
  const original = inputData[index]?.json || {};
  const title = original.title || 'Sans titre';
  const link = original.link || '';
  const source = original.source || '';
  return `${source} 📰 **${title}**\n${resume}\n🔗 ${link}`;
});
const content = `🛡️ **Veille SSI du ${new Date().toLocaleDateString('fr-FR')}**\n\n${lines.slice(0, 5).join('\n\n---\n\n')}`.substring(0, 1990);
return [{ json: { content } }];
